SELECT S.CONTRATO, COUNT(S.PK_SIAPE) AS QUANTIDADE FROM SERVIDOR S WHERE LOWER(S.AREA_INGRESSO) = LOWER('sociologia') AND LOWER(S.SIGLA_CAMPUS) = LOWER('for') AND SAIU_DO_IFG = FALSE AND S.CATEGORIA = 'DOCENTE' AND ((SELECT COUNT(*) FROM CALC_HORA_AULA_MEDIA C WHERE C.SIAPE = S.PK_SIAPE AND C.ANO = 2021 AND C.SEMESTRE = 2 AND LOWER(C.SIGLA_CAMPUS) = LOWER('for') AND LOWER(C.AREA_INGRESSO) = LOWER('sociologia')) > 0) GROUP BY S.CONTRATO HAVING COUNT(S.PK_SIAPE) = 1